/// GraphQL input → domain command over the shared serde wire shape: both sides are generated from
/// the same commands.yaml (camelCase), so the mapping is mechanical. `null`s are stripped first — an
/// unset GraphQL optional serializes as an explicit null, while the domain payloads model absence as a
/// MISSING key (`Option` fields / `#[serde(default)]` arrays).
fn to_command<C: serde::de::DeserializeOwned>(input: &impl serde::Serialize) -> async_graphql::Result<C> {
    let mut value = serde_json::to_value(input).map_err(|e| async_graphql::Error::new(e.to_string()))?;
    strip_nulls(&mut value);
    serde_json::from_value(value).map_err(|e| async_graphql::Error::new(e.to_string()))
}

fn strip_nulls(value: &mut serde_json::Value) {
    match value {
        serde_json::Value::Object(map) => {
            map.retain(|_, v| !v.is_null());
            for v in map.values_mut() {
                strip_nulls(v);
            }
        }
        serde_json::Value::Array(items) => {
            for v in items.iter_mut() {
                strip_nulls(v);
            }
        }
        _ => {}
    }
}

/// The acting user stamped on the event envelope (ADR-0041). Authn/ACL is a separate workstream: until
/// it lands, every mutation runs as the anonymous PUBLIC principal with a fresh correlation id (also
/// returned in the payload so the client can track the outcome on the read side).
fn request_actor(_ctx: &async_graphql::Context<'_>) -> application::ports::Actor {
    application::ports::Actor {
        user_id: uuid::Uuid::nil(),
        user_type: 0, // UserType::PUBLIC ordinal (enums are declaration-order integers, ADR-0037)
        correlation_id: uuid::Uuid::new_v4(),
        cause_id: None,
    }
}

fn domain_error(e: domain::shared::errors::DomainError) -> async_graphql::Error {
    async_graphql::Error::new(e.to_string())
}
